class FertilizerItem {
  final String name;
  final String nameHindi;
  final String image;
  final String description;
  final String descriptionHindi;
  final String nutrientContent;
  final String nutrientContentHindi;
  final String howToUse;
  final String howToUseHindi;
  final String whenToApply;
  final String whenToApplyHindi;
  final String dosage;
  final String dosageHindi;
  final String benefits;
  final String benefitsHindi;
  final String precautions;
  final String precautionsHindi;

  FertilizerItem({
    required this.name,
    required this.nameHindi,
    required this.image,
    this.description = '',
    this.descriptionHindi = '',
    this.nutrientContent = '',
    this.nutrientContentHindi = '',
    this.howToUse = '',
    this.howToUseHindi = '',
    this.whenToApply = '',
    this.whenToApplyHindi = '',
    this.dosage = '',
    this.dosageHindi = '',
    this.benefits = '',
    this.benefitsHindi = '',
    this.precautions = '',
    this.precautionsHindi = '',
  });
}

